#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

__kernel void lud_diagonal(__global float *a,
                           __local float *shadow,
                           int size,
                           int offset)
{
    int tx = (int)get_local_id(0);

    if (tx == 0) {
        int i, j, k;

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                shadow[i * BLOCK_SIZE + j] = a[(offset + i) * size + (offset + j)];
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = i; j < BLOCK_SIZE; j++) {
                float sum = shadow[i * BLOCK_SIZE + j];
                for (k = 0; k < i; k++) {
                    sum -= shadow[i * BLOCK_SIZE + k] * shadow[k * BLOCK_SIZE + j];
                }
                shadow[i * BLOCK_SIZE + j] = sum;
            }

            for (j = i + 1; j < BLOCK_SIZE; j++) {
                float sum = shadow[j * BLOCK_SIZE + i];
                for (k = 0; k < i; k++) {
                    sum -= shadow[j * BLOCK_SIZE + k] * shadow[k * BLOCK_SIZE + i];
                }
                shadow[j * BLOCK_SIZE + i] = sum / shadow[i * BLOCK_SIZE + i];
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                a[(offset + i) * size + (offset + j)] = shadow[i * BLOCK_SIZE + j];
            }
        }
    }
}

__kernel void lud_perimeter(__global float *a,
                            __local float *dia,
                            __local float *peri_row,
                            __local float *peri_col,
                            int size,
                            int offset)
{
    int tx = (int)get_local_id(0);
    int chunk_idx = (int)get_group_id(0);

    if (tx == 0) {
        int i, j, k;
        int chunks = (size - offset) / BLOCK_SIZE - 1;

        if (chunk_idx >= chunks) {
            return;
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                dia[i * BLOCK_SIZE + j] = a[(offset + i) * size + (offset + j)];
            }
        }

        {
            int j_global = offset + BLOCK_SIZE * (chunk_idx + 1);

            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    peri_row[i * BLOCK_SIZE + j] = a[(offset + i) * size + (j_global + j)];
                }
            }

            for (j = 0; j < BLOCK_SIZE; j++) {
                for (i = 0; i < BLOCK_SIZE; i++) {
                    float sum = 0.0f;
                    for (k = 0; k < i; k++) {
                        sum += dia[i * BLOCK_SIZE + k] * peri_row[k * BLOCK_SIZE + j];
                    }
                    peri_row[i * BLOCK_SIZE + j] -= sum;
                }
            }

            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    a[(offset + i) * size + (j_global + j)] = peri_row[i * BLOCK_SIZE + j];
                }
            }
        }

        {
            int i_global = offset + BLOCK_SIZE * (chunk_idx + 1);

            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    peri_col[i * BLOCK_SIZE + j] = a[(i_global + i) * size + (offset + j)];
                }
            }

            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    float sum = 0.0f;
                    for (k = 0; k < j; k++) {
                        sum += peri_col[i * BLOCK_SIZE + k] * dia[k * BLOCK_SIZE + j];
                    }
                    peri_col[i * BLOCK_SIZE + j] =
                        (peri_col[i * BLOCK_SIZE + j] - sum) / dia[j * BLOCK_SIZE + j];
                }
            }

            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    a[(i_global + i) * size + (offset + j)] = peri_col[i * BLOCK_SIZE + j];
                }
            }
        }
    }
}

__kernel void lud_internal(__global float *a,
                           __local float *temp_top,
                           __local float *temp_left,
                           int size,
                           int offset)
{
    int lx = (int)get_local_id(0);
    int ly = (int)get_local_id(1);
    int block_x = (int)get_group_id(0);
    int block_y = (int)get_group_id(1);

    if (lx == 0 && ly == 0) {
        int i, j, k;
        int i_global = offset + BLOCK_SIZE * (block_y + 1);
        int j_global = offset + BLOCK_SIZE * (block_x + 1);

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                temp_top[i * BLOCK_SIZE + j] = a[(offset + i) * size + (j_global + j)];
                temp_left[i * BLOCK_SIZE + j] = a[(i_global + i) * size + (offset + j)];
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < BLOCK_SIZE; k++) {
                    sum += temp_left[i * BLOCK_SIZE + k] * temp_top[k * BLOCK_SIZE + j];
                }
                a[(i_global + i) * size + (j_global + j)] -= sum;
            }
        }
    }
}
